const SetValue = async (context) => {
    //Code Here
    const heatingType1 = context?.Form?.HeatingSourcePage?.ExistingHeatingType?.Value || "";
    // const heatingType2 = context?.Form?.HeatingSourcePage?.SecondaryExistingHeatingType?.Value || "";
    const heatingFuel1 = context?.Form?.HeatingSourcePage?.ExistingHeatingFuel?.Value || "";
    // const heatingFuel2 = context?.Form?.HeatingSourcePage?.SecondaryExistingHeatingFuel?.Value || "";
    const coolingType1 = context?.Form?.CoolingSourcePage?.ExistingPrimaryCoolingType?.Value || "";
    // const coolingType2 = context?.Form?.CoolingSourcePage?.ExistingCoolingType2?.Value || "";

    // rDXGF - Central AC with Gas Furnace
    // rDXHP - Central HP with Electric Resistance Backup
    // rNCEH - No Cooling, Electric Baseboard Heating
    // rNCGF - No Cooling, Gas Furnace

    const isCentralAC1 = coolingType1 == "Package" || 
                       coolingType1 == "Split" || 
                       coolingType1 == "Central Evaporative Cooler";

    /* const isCentralAC2 = coolingType2 == "Package" || 
                       coolingType2 == "Split" || 
                       coolingType2 == "Central Evaporative Cooler"; */

    const isGasFuel1 = (heatingFuel1 == "Natural Gas" || heatingFuel1 == "Propane");
    // const isGasFuel2 = (heatingFuel2 == "Natural Gas" || heatingFuel2 == "Propane");

    if (isCentralAC1 && isFurnace1 && isGasFuel1) {
        return "rDXGF";
    }

    if (heatingType1 == "Heat Pump (or Mini-Split)") {
        return "rDXHP";
    }

     if (coolingType1 == "No Cooling" && isFurnace1 && isGasFuel1) {
        return "rNCGF"
    }

    /* no electric baseboard heating option 
    if (coolingType1 == "No Cooling") {
        return "rNCEH"
    } */ 


    if (!heatingType1 || !heatingFuel1 || !coolingType1) {
    return "";
}
    return `${heatingType1}-${heatingFuel1}-${coolingType1}`;
