    const eeStatus = context?.Form?.SubmissionReviewPage?.ReviewStatus?.Value || "";
    const spvStatus = context?.Form?.SubmissionReviewPage?.SPVReviewStatus?.Value || "";

    // Compute suffix once instead of checking on every call
    const deferralValue = context?.Form?.CustomerInformationPage?.DoesHomeRequireADeferral?.Value || "";
    const suffix = deferralValue == "YES" ? " (Deferred)" 
                 : deferralValue == "PARTIAL" ? " (Partial)" 
                 : "";

    // Simple concatenation - faster than function call
    const append = (status) => status + suffix;

    if (eeStatus == "Pending SnuggPro Review") return append("Pending SnuggPro Review");
    if (eeStatus == "Pending Waiver" || spvStatus == "Pending Waiver") return append("Pending Waiver");

