    if (!eeStatus && spvStatus == "Canceled") return append("SPV Canceled");

    if (eeStatus == "Assessment Approved" && spvStatus == "Assessment Approved") return append("EE & SPV Approved");
    if (eeStatus == "Assessment Approved" && spvStatus == "Pending Review") return append("EE Approved & SPV Pending Review");
    if (eeStatus == "Pending Review" && spvStatus == "Assessment Approved") return append("EE Pending Review & SPV Approved");
    if (eeStatus == "Assessment Approved" && !spvStatus) return append("EE Approved");
    if (!eeStatus && spvStatus == "Assessment Approved") return append("SPV Approved");

    if (eeStatus == "Corrections Required" && spvStatus == "Corrections Required") return append("EE & SPV Corrections Required");
    if (eeStatus == "Corrections Required" && !spvStatus) return append("EE Corrections Required");
    if (!eeStatus && spvStatus == "Corrections Required") return append("SPV Corrections Required");

    if (eeStatus == "Pending Review" && spvStatus == "Pending Review") return append("EE & SPV Ready for Review");
    if (eeStatus == "Pending Review" && !spvStatus) return append("EE Ready for Review");
    if (!eeStatus && spvStatus == "Pending Review") return append("SPV Ready for Review");

    return append("Draft Pending");
